// ---- Basic LazyColumn ----
@Composable
fun BasicLazyColumn() {
    val items = (1..100).map { "Item $it" }

    LazyColumn(
        modifier = Modifier.fillMaxSize(),
        contentPadding = PaddingValues(16.dp),
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        items(items) { item ->
            Text(
                text = item,
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color.LightGray)
                    .padding(16.dp)
            )
        }
    }
}

// ---- LazyColumn with headers ----
@Composable
fun LazyColumnWithHeaders() {
    val sections = mapOf(
        "A" to listOf("Apple", "Apricot", "Avocado"),
        "B" to listOf("Banana", "Blueberry", "Blackberry"),
        "C" to listOf("Cherry", "Coconut", "Cranberry")
    )

    LazyColumn(
        modifier = Modifier.fillMaxSize(),
        contentPadding = PaddingValues(16.dp),
        verticalArrangement = Arrangement.spacedBy(4.dp)
    ) {
        sections.forEach { (header, items) ->
            stickyHeader {
                Text(
                    text = header,
                    fontSize = 20.sp,
                    fontWeight = FontWeight.Bold,
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color.Blue)
                        .padding(8.dp)
                )
            }
            items(items) { item ->
                Text(
                    text = item,
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color.LightGray)
                        .padding(12.dp)
                )
            }
        }
    }
}

