}

// ---- LazyColumn with complex items ----
data class Contact(
    val name: String,
    val phone: String,
    val isOnline: Boolean
)

@Composable
fun LazyColumnComplex() {
    val contacts = listOf(
        Contact("Alice", "555-0101", true),
        Contact("Bob", "555-0102", false),
        Contact("Charlie", "555-0103", true),
        Contact("Diana", "555-0104", false),
        Contact("Eve", "555-0105", true)
    )

    LazyColumn(
        modifier = Modifier.fillMaxSize(),
        contentPadding = PaddingValues(16.dp),
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        items(
            items = contacts,
            key = { it.name }
        ) { contact ->
            ContactItem(contact = contact)
        }
    }
}

@Composable
fun ContactItem(contact: Contact) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(
            containerColor = if (contact.isOnline) Color.White else Color.LightGray
        )
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column(
                modifier = Modifier.weight(1f)
            ) {
                Text(
                    text = contact.name,
                    fontSize = 18.sp,
                    fontWeight = FontWeight.Bold
                )
                Text(
                    text = contact.phone,
                    fontSize = 14.sp,
                    color = Color.Gray
                )
            }
            Text(
                text = if (contact.isOnline) "🟢 Online" else "⚪ Offline",
                color = if (contact.isOnline) Color.Green else Color.Gray
            )
        }
    }
}

// ---- LazyColumn with state ----
@Composable
fun LazyColumnWithState() {
    val items = (1..100).map { "Item $it" }
    val listState = rememberLazyListState()

    Column {
        Text(
            text = "First visible: ${listState.firstVisibleItemIndex}",
            modifier = Modifier.padding(16.dp)
        )

        LazyColumn(
            modifier = Modifier.fillMaxSize(),
            state = listState,
            contentPadding = PaddingValues(16.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            items(items) { item ->
                Text(
                    text = item,
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color.LightGray)
                        .padding(16.dp)
                )
            }
        }
    }
}

// ---- LazyColumn with scroll to top ----
@Composable
fun LazyColumnWithScrollToTop() {
    val items = (1..100).map { "Item $it" }
    val listState = rememberLazyListState()
    val coroutineScope = rememberCoroutineScope()

    Column(
        modifier = Modifier.fillMaxSize()
    ) {
        Button(
            onClick = {
                coroutineScope.launch {
                    listState.scrollToItem(0)
                }
            },
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp)
        ) {
            Text("Scroll to top")
        }

        LazyColumn(
            modifier = Modifier.fillMaxSize(),
            state = listState,
            contentPadding = PaddingValues(16.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            items(items) { item ->
                Text(
                    text = item,
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color.LightGray)
                        .padding(16.dp)
                )
            }
        }
    }
}

