data class Contact(val name: String, val phone: String, var isFavorite: Boolean = false)

@Composable
fun ContactList() {
    val contacts = remember {
        mutableStateListOf<Contact>().apply {
            addAll(generateContacts())
        }
    }

    val grouped = contacts.groupBy { it.name.first().uppercase() }
    val sortedKeys = grouped.keys.sorted()

    val listState = rememberLazyListState()
    val coroutineScope = rememberCoroutineScope()

    Column(
        modifier = Modifier.fillMaxSize()
    ) {
        Button(
            onClick = {
                coroutineScope.launch {
                    listState.scrollToItem(0)
                }
            },
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp)
        ) {
            Text("Scroll to top")
        }

        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .weight(1f),
            state = listState,
            contentPadding = PaddingValues(horizontal = 16.dp, vertical = 8.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            sortedKeys.forEach { letter ->
                stickyHeader {
                    Text(
                        text = letter,
                        fontSize = 20.sp,
                        fontWeight = FontWeight.Bold,
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color.Blue)
                            .padding(8.dp)
                    )
                }

                items(
                    items = grouped[letter] ?: emptyList(),
                    key = { it.name }
                ) { contact ->
                    ContactItem(
                        contact = contact,
                        onFavoriteToggle = {
                            contact.isFavorite = !contact.isFavorite
                        }
                    )
                }
            }
        }
    }
}

@Composable
fun ContactItem(
    contact: Contact,
    onFavoriteToggle: () -> Unit
) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(
            containerColor = if (contact.isFavorite) Color(0xFFFFF8E1) else Color.White
        )
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column(
                modifier = Modifier.weight(1f)
            ) {
                Text(
                    text = contact.name,
                    fontSize = 18.sp,
                    fontWeight = FontWeight.Bold
                )
                Text(
                    text = contact.phone,
                    fontSize = 14.sp,
                    color = Color.Gray
                )
            }

            IconButton(
                onClick = onFavoriteToggle
            ) {
                Icon(
                    imageVector = if (contact.isFavorite) Icons.Default.Star else Icons.Default.StarBorder,
                    contentDescription = if (contact.isFavorite) "Unfavorite" else "Favorite",
                    tint = if (contact.isFavorite) Color(0xFFFFC107) else Color.Gray
                )
            }
        }
    }
}

fun generateContacts(): List<Contact> {
    val names = listOf(
        "Alice", "Bob", "Charlie", "Diana", "Eve",
        "Frank", "Grace", "Henry", "Ivy", "Jack",
        "Karen", "Leo", "Mia", "Noah", "Olivia"
    )
    return names.mapIndexed { i, name ->
        Contact(
            name = name,
            phone = "555-${(1000 + i * 100).toString().padStart(4, '0')}",
            isFavorite = i % 3 == 0
        )
    }
}

